def solve(startUrl, edges):
    from urllib.parse import urlparse
    from collections import defaultdict, deque
    graph = defaultdict(list)
    for line in edges:
        parts = line.strip().split()
        if len(parts) == 2:
            graph[parts[0]].append(parts[1])
    start_host = urlparse(startUrl).hostname
    visited = {startUrl}
    queue = deque([startUrl])
    while queue:
        url = queue.popleft()
        for nb in graph[url]:
            if nb not in visited and urlparse(nb).hostname == start_host:
                visited.add(nb)
                queue.append(nb)
    return '\n'.join(sorted(visited))

